    TrieNode* node = root;
    long long maxXor = 0;
    for (int i = 31; i >= 0; --i) {
        int bit = (num >> i) & 1;
        int toggledBit = 1 - bit;
        if (node->children[toggledBit] != nullptr) {
            maxXor |= (1LL << i);
            node = node->children[toggledBit];
        } else {
            node = node->children[bit];
        }
    }
    return maxXor;
}

